import (
	"github.com/openmeterio/openmeter/openmeter/billing/charges/flatfee/service/realizations"
)

svc, err := realizations.New(realizations.Config{
	Adapter:       adapter,
	Handler:       handler,
	Lineage:       lineageSvc,
	RatingService: ratingSvc,
})
if err != nil {
	return err
}

result, err := svc.AllocateCreditsOnly(ctx, realizations.AllocateCreditsOnlyInput{
	Charge:             charge,
	Amount:             amount,
	CurrencyCalculator: calc,
})
// On success: result.Allocated == RoundToPrecision(sum of handler allocations)
// Realizations and lineage segments are persisted atomically.
